USE bandjougou;
SET FOREIGN_KEY_CHECKS = 0;
CREATE TABLE IF NOT EXISTS ROLE (idR INT PRIMARY KEY, descriptionR VARCHAR(255)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS PERMISSION (idP INT PRIMARY KEY,descriptionP VARCHAR(255)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS MARITIMEZONE (idMz INT PRIMARY KEY,nameMz VARCHAR(100),typeMz VARCHAR(50),latitudeMz DECIMAL(10, 8),longitudeMz DECIMAL(11, 8),radiusMz FLOAT,descriptionMz TEXT) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS DEVICETYPE (idDt INT PRIMARY KEY,nameDt VARCHAR(100),actionDt VARCHAR(100)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS BOAT (idB INT PRIMARY KEY,nameB VARCHAR(100),maxspeedB FLOAT,capacityB INT,registrationB VARCHAR(50),lenghtB FLOAT) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS USER (idU INT PRIMARY KEY,usernameU VARCHAR(50),surnameU VARCHAR(100),nameU VARCHAR(100),emailU VARCHAR(150),pwdU VARCHAR(255),crea_date DATETIME,idR INT,idB INT,FOREIGN KEY (idR) REFERENCES ROLE(idR),FOREIGN KEY (idB) REFERENCES BOAT(idB)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS ROOM (idRo INT PRIMARY KEY, nameRo VARCHAR(100), typeRo VARCHAR(50), descriptionRo TEXT, idB INT, FOREIGN KEY (idB) REFERENCES BOAT(idB)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS DEVICE (idD INT PRIMARY KEY, nameD VARCHAR(100), statusD VARCHAR(50), idDt INT, idRo INT, FOREIGN KEY (idDt) REFERENCES DEVICETYPE(idDt), FOREIGN KEY (idRo) REFERENCES ROOM(idRo)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS DOOR (idDo INT PRIMARY KEY, nameDo VARCHAR(100), statusDo VARCHAR(50), idRo1 INT, idRo2 INT, FOREIGN KEY (idRo1) REFERENCES ROOM(idRo), FOREIGN KEY (idRo2) REFERENCES ROOM(idRo)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS RESEARCHRESULT (idRr INT PRIMARY KEY, typeRr VARCHAR(100), dataRr TEXT, reliabilityRr FLOAT, idD INT, FOREIGN KEY (idD) REFERENCES DEVICE(idD)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS RESEARCH (idRs INT PRIMARY KEY, typeRs VARCHAR(100), paramRs TEXT,research_dateRs DATETIME ,  idRr INT, idMz INT, idB INT , statusRs VARCHAR(50) ,    FOREIGN KEY (idRr) REFERENCES RESEARCHRESULT(idRr),FOREIGN KEY (idB) REFERENCES BOAT(idB) ,  FOREIGN KEY (idMz) REFERENCES MARITIMEZONE(idMz)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS MEASURE (idM INT PRIMARY KEY, typeM VARCHAR(100), dataM TEXT,dateM  DATETIME,  idD INT, FOREIGN KEY (idD) REFERENCES DEVICE(idD)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS DISPOSE_OF (idR INT, idP INT, PRIMARY KEY (idR, idP), FOREIGN KEY (idR) REFERENCES ROLE(idR), FOREIGN KEY (idP) REFERENCES PERMISSION(idP)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS IS_ALLOWED_TO (idU INT, idP INT, idD INT, action VARCHAR(255), PRIMARY KEY (idU, idP, idD), FOREIGN KEY (idU) REFERENCES USER(idU), FOREIGN KEY (idP) REFERENCES PERMISSION(idP), FOREIGN KEY (idD) REFERENCES DEVICE(idD)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS CONDUCTS (idU INT, idRs INT, PRIMARY KEY (idU, idRs), FOREIGN KEY (idU) REFERENCES USER(idU), FOREIGN KEY (idRs) REFERENCES RESEARCH(idRs)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS RECEIVED_DATA (idM INT, idRr INT,  PRIMARY KEY (idM, idRr), FOREIGN KEY (idM) REFERENCES MEASURE(idM), FOREIGN KEY (idRr) REFERENCES RESEARCHRESULT(idRr)) ENGINE=InnoDB;

SET FOREIGN_KEY_CHECKS = 1;
